pub(crate) const fn tier_weight(tier: Tier) -> f32 {
    match tier {
        Tier::Hot => 1.0,
        Tier::Warm => 0.7,
        Tier::Cold => 0.3,
        Tier::Forgotten => 0.0,
    }
}
pub(crate) fn check_rbac_scope(
    opts: &RetrievalOpts,
    scope_id: &str,
    retriever_name: &str,
    start: &Instant,
) -> Option<RetrievalResult> {
    if let Some(ref perms) = opts.permissions
        && let AgentPermission::ReadWrite { scopes } = perms
            && !scopes.iter().any(|s| s == scope_id || s == "*") {
                info!(
                    retriever = retriever_name,
                    scope_id,
                    "RBAC denied: agent lacks scope access"
                );
                return Some(RetrievalResult {
                    results: Vec::new(),
                    metrics: RetrievalMetrics {
                        latency_ms: start.elapsed().as_millis() as u64,
                        embed_latency_ms: 0,
                        search_latency_ms: 0,
                        hnsw_latency_ms: 0,
                        graph_latency_ms: 0,
                        filter_latency_ms: 0,
                        cold_scan_latency_ms: 0,
                        vector_results: 0,
                        cold_results: 0,
                        graph_expanded: 0,
                        graph_reinforced: 0,
                        post_filter_count: 0,
                        retriever_name: retriever_name.to_string(),
                        bm25_latency_ms: None,
                        bm25_results: None,
                        fusion_method: None,
                        fusion_latency_ms: None,
                        stages: None,
                    },
                    query_embedding: None,
                });
            }
    None
}
